  opacity: 1;
  margin-top: 10px;
  border-left: none;
  padding-left: 0;
}

.gpa-badge {
  display: inline-block;
  background-color: rgba(23, 124, 114, 0.1);
  color: #177c72;
  padding: 4px 12px;
  border-radius: 6px;
  font-weight: 600;
  font-size: 0.9rem;
  margin-top: 8px;
  border: 1px solid rgba(23, 124, 114, 0.2);
}

html.dark-mode .gpa-badge {
  background-color: rgba(45, 212, 191, 0.1);
  color: #4fffd3;
  border-color: rgba(45, 212, 191, 0.3);
  box-shadow: 0 0 10px rgba(45, 212, 191, 0.1);
}

/* Header Redesign */
header nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

nav ul {
  display: flex;
  gap: 1rem;
  grid-template-columns: none; /* Reset grid */
  margin: 0; /* Reset margin if any */
}

.header-right {
  display: flex;
  align-items: center;
  gap: 1.5rem;
}

.icon-link, .icon-btn {
  color: var(--text-primary);
  font-size: 1.2rem;
  background: none;
  border: none;
  cursor: pointer;
  padding: 0.5rem;
  transition: color 0.3s ease, transform 0.2s ease;
  display: flex;
  align-items: center;
  justify-content: center;
}

.icon-link:hover, .icon-btn:hover {
  color: var(--dark-green);
  transform: translateY(-2px);
}

/* Dark Mode Toggle Specifics */
.icon-btn:focus {
  outline: none;
}

/* Ensure icons are visible in dark mode */
html.dark-mode .icon-link, 
html.dark-mode .icon-btn {
  color: #e0e0e0;
}

html.dark-mode .icon-link:hover, 
html.dark-mode .icon-btn:hover {
  color: var(--light-green);
}
